authRouter.post("/register", async (c) => {
  try {
    const { username, password, displayName, email, phone, facebook } = await c.req.json();
    if (!username || !password || !email) {
      return c.json({ success: false, error: "T\xEAn \u0111\u0103ng nh\u1EADp, email v\xE0 m\u1EADt kh\u1EA9u l\xE0 b\u1EAFt bu\u1ED9c" }, 400);
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) return c.json({ success: false, error: "Email kh\xF4ng h\u1EE3p l\u1EC7" }, 400);
    const strongRegex = new RegExp("^(?=.*[a-z])(?=.*[A-Z])(?=.*[0-9])(?=.*[!@#\\$%\\^&\\*])(?=.{8,})");
    if (!strongRegex.test(password)) {
      return c.json({ success: false, error: "M\u1EADt kh\u1EA9u ph\u1EA3i t\u1EEB 8 k\xFD t\u1EF1, g\u1ED3m ch\u1EEF hoa, th\u01B0\u1EDDng, s\u1ED1 v\xE0 k\xFD t\u1EF1 \u0111\u1EB7c bi\u1EC7t" }, 400);
    }
    const db = getDb(c.env.DB);
    const [existingUser] = await db.select({ id: users.id }).from(users).where(eq(users.username, username));
    if (existingUser) return c.json({ success: false, error: "T\xEAn \u0111\u0103ng nh\u1EADp \u0111\xE3 t\u1ED3n t\u1EA1i" }, 400);
    const [existingEmail] = await db.select({ id: users.id }).from(users).where(eq(users.email, email));
    if (existingEmail) return c.json({ success: false, error: "Email n\xE0y \u0111\xE3 \u0111\u01B0\u1EE3c \u0111\u0103ng k\xFD" }, 400);
    const hashedPw = await hash(password, 10);
    const verToken = generateToken();
    await db.insert(users).values({
      username,
      password: hashedPw,
      displayName: displayName || username,
      email,
      phone: phone || "",
      // facebook: facebook || '', // Removed from schema.ts
      role: "viewer",
      emailVerified: false,
      verificationToken: verToken
    });
    return c.json({
      success: true,
      message: `\u0110\u0103ng k\xFD th\xE0nh c\xF4ng! Vui l\xF2ng li\xEAn h\u1EC7 admin \u0111\u1EC3 k\xEDch ho\u1EA1t t\xE0i kho\u1EA3n ho\u1EB7c l\xE0m theo email (n\u1EBFu c\xF3).`
    }, 201);
  } catch (err) {
    return c.json({ success: false, error: err.message }, 500);
  }
});

